	Rationale        string                     `json:"rationale,omitempty"`
	Findings         []Finding                  `json:"findings,omitempty"`
	Error            string                     `json:"error,omitempty"`
	EvidenceAssembly *EvidenceAssemblyTelemetry `json:"evidence_assembly,omitempty"`
