			body := ReviewErrorEventBody(class, attemptCount, report.ResultRev, detail)
			if attemptCount >= maxRetries {
				_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
					Kind:      "review-manual-required",
					Summary:   class,
